function setCookie(name, value, days) {
    const date = new Date();
    date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000));
    document.cookie = name + "=" + value + "; expires=" + date.toUTCString() + "; path=/";
}

function getCookie(name) {
    const nameEQ = name + "=";
    const ca = document.cookie.split(';');
    for (let i = 0; i < ca.length; i++) {
        let c = ca[i];
        while (c.charAt(0) === ' ') c = c.substring(1, c.length);
        if (c.indexOf(nameEQ) === 0) return c.substring(nameEQ.length, c.length);
    }
    return null;
}

function rememberMe(username, passwordHash) {
    setCookie('username', username, 30);
    setCookie('passwordHash', passwordHash, 30);
}

function autoLogin() {
    const username = getCookie('username');
    const passwordHash = getCookie('passwordHash');
    if (username && passwordHash) {
        // Simulate login
        console.log(`Auto-logging in as ${username}`);
        // Call your actual login function here with username and passwordHash
    }
}

